+            NavigateResult::Generic {
+                resource_type,
+                data,
+            } => {
+                assert_eq!(resource_type, "tooling/metrics");
+                assert!(data["health_level"].is_string());
+                assert!(data["tools"].is_array());
+            }
+            other => panic!("unexpected tooling metrics result: {other:?}"),
+        }
